#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10,INF=1e8;

struct Edge{
    int x,y,a,b;
    bool operator<(Edge u)const{
        return a<u.a;
    }
}e[N];

struct Node{
    int s[2],f,v,mx,rev;
}t[N];

int n,m,f[N],stk[N];

int father(int x){
    return f[x]==x?x:f[x]=father(f[x]);
}

void pushrev(int x){
    swap(t[x].s[0],t[x].s[1]);
    t[x].rev^=1;
}

void pushup(int x){
    t[x].mx=x;
    if(t[t[t[x].s[0]].mx].v>t[t[x].mx].v) t[x].mx=t[t[x].s[0]].mx;
    if(t[t[t[x].s[1]].mx].v>t[t[x].mx].v) t[x].mx=t[t[x].s[1]].mx;
}

void pushdown(int x){
    if(t[x].rev){
        if(t[x].s[0]) pushrev(t[x].s[0]);
        if(t[x].s[1]) pushrev(t[x].s[1]);
        t[x].rev=0;
    }
}

bool isroot(int x){
    return t[t[x].f].s[0]!=x && t[t[x].f].s[1]!=x;
}

void Rotate(int x){
    int y=t[x].f,z=t[y].f,k=(t[y].s[1]==x);
    if(!isroot(y)) t[z].s[t[z].s[1]==y]=x;
    t[x].f=z;
    t[y].s[k]=t[x].s[k^1],t[t[x].s[k^1]].f=y;
    t[x].s[k^1]=y,t[y].f=x;
    pushup(y),pushup(x);
}

void Splay(int x){
    int top=0,u=x;
    stk[++top]=u;
    while(!isroot(u)) stk[++top]=u=t[u].f;
    while(top) pushdown(stk[top--]);
    while(!isroot(x)){
        int y=t[x].f,z=t[y].f;
        if(!isroot(y))
            if((t[y].s[1]==x)^(t[z].s[1]==y)) Rotate(x);
            else Rotate(y);
        Rotate(x);
    }
}

void Access(int x){
    int z=x;
    for(int y=0;x;y=x,x=t[x].f){
        Splay(x);
        t[x].s[1]=y,pushup(x);
    }
    Splay(z);
}

void Makeroot(int x){
    Access(x);
    pushrev(x);
}

int findroot(int x){
    Access(x);
    while(t[x].s[0]) pushdown(x),x=t[x].s[0];
    Splay(x);
    return x;
}

void Split(int x,int y){
    Makeroot(x);
    Access(y);
}

void Link(int x,int y){
    Makeroot(x);
    if(findroot(y)!=x) t[x].f=y;
}

void Cut(int x,int y){
    Makeroot(x);
    if(findroot(y)==x && t[x].s[1]==y && !t[y].s[0]){
        t[y].f=t[x].s[1]=0;
        pushup(x);
    }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
        scanf("%d%d%d%d",&e[i].x,&e[i].y,&e[i].a,&e[i].b);
    sort(e+1,e+m+1);
    for(int i=1;i<=n;i++)
        f[i]=i;
    int ans=INF;
    for(int i=1;i<=m;i++){
        t[n+i].v=e[i].b;
        t[n+i].mx=n+i;
        int x=e[i].x,y=e[i].y,a=e[i].a,b=e[i].b;
        if(father(x)==father(y)){
            Split(x,y);
            int p=t[y].mx;
            if(t[p].v>b){
                Cut(e[p-n].x,p),Cut(p,e[p-n].y);
                Link(x,n+i),Link(n+i,y);
            }
        }else{
            f[f[x]]=f[y];
            Link(x,n+i),Link(n+i,y);
        }
        if(father(1)==father(n)){
            Split(1,n);
            ans=min(ans,a+t[t[n].mx].v);
        }
    }
    if(ans==INF)
        printf("-1");
    else
        printf("%d",ans);
    return 0;
}
